import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../api/axiosConfig';
import { Zap, TrendingUp, TrendingDown, ChevronLeft, ChevronRight, Box, Activity, Shield } from 'lucide-react';

const LiveMarketPage = () => {
    // 1. Direct Context Access
    const { token } = useContext(AuthContext);

    // --- STATE MANAGEMENT ---
    const [history, setHistory] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [stocks, setStocks] = useState([]);
    const [isConnected, setIsConnected] = useState(false);

    // --- 2. DATA INITIALIZATION (FETCH VAULT) ---
    useEffect(() => {
        const fetchVault = async () => {
            try {
                const res = await api.get('/portfolio/history');
                setHistory(res.data);
                if (res.data.length > 0) {
                    initializeStocks(res.data[0].holdings);
                }
            } catch (err) {
                console.error("VAULT_SYNC_ERROR: TERMINAL_OFFLINE");
            }
        };
        fetchVault();
    }, []);

    const initializeStocks = (holdingsData) => {
        try {
            // Handle double-stringified JSON from PostgreSQL
            let tickers = typeof holdingsData === 'string' ? JSON.parse(holdingsData) : holdingsData;
            if (typeof tickers === 'string') tickers = JSON.parse(tickers);
            
            const initialSet = tickers.map(t => ({
                ticker: t,
                price: Math.floor(Math.random() * 1500) + 400, // Starting simulated price
                change: 0.00
            }));
            setStocks(initialSet);
        } catch (e) {
            setStocks([]);
        }
    };

    // --- 3. LIVE WEBSOCKET PULSE ---
    useEffect(() => {
        if (!token) return;

        const ws = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);

        ws.onopen = () => setIsConnected(true);

        ws.onmessage = (event) => {
            // Logic: On every pulse, simulate volatility for the current node's tickers
            setStocks(prev => prev.map(s => {
                const move = (Math.random() - 0.5) * 5.5; // Simulated price shift
                return {
                    ...s,
                    price: parseFloat((s.price + move).toFixed(2)),
                    change: parseFloat(move.toFixed(2))
                };
            }));
        };

        ws.onclose = () => setIsConnected(false);
        return () => ws.close();
    }, [token, currentIndex]); // Resets connection context when node changes

    // --- 4. NAVIGATION LOGIC ---
    const navigate = (direction) => {
        let newIndex = currentIndex + direction;
        if (newIndex >= 0 && newIndex < history.length) {
            setCurrentIndex(newIndex);
            initializeStocks(history[newIndex].holdings);
        }
    };

    const activeNode = history[currentIndex];

    return (
        <div className="reveal-node" style={containerStyle}>
            {/* Header / Status Bar */}
            <div style={statusHeader}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <Activity size={20} color={isConnected ? "#10b981" : "#ef4444"} />
                    <h2 style={titleStyle}>LIVE_MARKET_MONITOR</h2>
                </div>
                <div style={connectionBadge(isConnected)}>
                    {isConnected ? 'NODE_STABLE' : 'NODE_RECONNECTING'}
                </div>
            </div>

            {/* Navigation Controls */}
            <div style={navBar}>
                <button 
                    onClick={() => navigate(1)} 
                    disabled={currentIndex === history.length - 1}
                    style={navBtn(currentIndex === history.length - 1)}
                >
                    <ChevronLeft size={20}/> PREVIOUS_STRATEGY
                </button>

                <div style={nodeContext}>
                    <Box size={14} color="var(--accent-primary)" />
                    <div style={nodeMeta}>
                        <span style={nodeLabel}>ACTIVE_NODE_ID: {activeNode?.id || '---'}</span>
                        <span style={nodeGoal}>{activeNode ? activeNode.goal.substring(0, 40) : 'LOADING_NODES...'}...</span>
                    </div>
                    <div style={counterTag}>{currentIndex + 1} / {history.length}</div>
                </div>

                <button 
                    onClick={() => navigate(-1)} 
                    disabled={currentIndex === 0}
                    style={navBtn(currentIndex === 0)}
                >
                    NEXT_STRATEGY <ChevronRight size={20}/>
                </button>
            </div>

            {/* Live Ticker Grid */}
            <div style={gridStyle}>
                {stocks.map((stock, i) => (
                    <div key={i} style={stockCard(stock.change >= 0)}>
                        <div style={cardHeader}>
                            <span style={tickerText}>{stock.ticker}</span>
                            <Shield size={12} color="var(--text-muted)" />
                        </div>
                        <div style={priceContainer}>
                            <span style={priceLabel}>MARKET_VAL</span>
                            <span style={priceText}>₹{stock.price.toLocaleString()}</span>
                        </div>
                        <div style={changeRow(stock.change >= 0)}>
                            {stock.change >= 0 ? <TrendingUp size={14}/> : <TrendingDown size={14}/>}
                            <span style={{fontWeight: 800}}>{stock.change >= 0 ? '+' : ''}{stock.change}%</span>
                            <Zap size={12} style={{marginLeft: 'auto'}} />
                        </div>
                    </div>
                ))}
                
                {history.length > 0 && stocks.length === 0 && (
                    <div style={emptyState}>NO_TICKERS_DEFINED_FOR_THIS_NODE</div>
                )}
            </div>
        </div>
    );
};

/* --- Terminal UI Styles (Emerald x Charcoal) --- */
const containerStyle = { padding: '2rem', maxWidth: '1200px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '2rem' };

const statusHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid var(--surface-border)', paddingBottom: '1rem' };
const titleStyle = { margin: 0, fontSize: '1.2rem', fontWeight: 900, color: 'var(--text-primary)', letterSpacing: '-0.02em' };
const connectionBadge = (online) => ({
    padding: '4px 12px', borderRadius: '4px', fontSize: '0.6rem', fontWeight: 900, fontFamily: 'monospace',
    background: online ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)',
    color: online ? '#10b981' : '#ef4444', border: `1px solid ${online ? '#10b981' : '#ef4444'}`
});

const navBar = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: 'var(--surface-glass)', padding: '1rem 1.5rem', borderRadius: '16px', border: '1px solid var(--surface-border)' };
const nodeContext = { display: 'flex', alignItems: 'center', gap: '15px' };
const nodeMeta = { display: 'flex', flexDirection: 'column' };
const nodeLabel = { fontSize: '0.55rem', color: 'var(--text-muted)', fontWeight: 800, letterSpacing: '0.1em' };
const nodeGoal = { fontSize: '0.85rem', color: 'var(--text-primary)', fontWeight: 700 };
const counterTag = { fontSize: '0.65rem', fontWeight: 900, color: 'var(--accent-primary)', background: 'rgba(255,255,255,0.03)', padding: '4px 8px', borderRadius: '4px' };

const navBtn = (disabled) => ({
    background: 'none', border: 'none', color: disabled ? 'var(--text-muted)' : 'var(--accent-primary)',
    cursor: disabled ? 'default' : 'pointer', fontSize: '0.7rem', fontWeight: 800, fontFamily: 'monospace',
    display: 'flex', alignItems: 'center', gap: '6px', opacity: disabled ? 0.3 : 1, transition: 'all 0.2s'
});

const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))', gap: '1.5rem' };
const stockCard = (up) => ({
    padding: '1.5rem', background: 'var(--surface-glass)', border: '1px solid var(--surface-border)',
    borderRadius: '20px', position: 'relative', overflow: 'hidden', borderLeft: `4px solid ${up ? '#10b981' : '#ef4444'}`
});

const cardHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.2rem' };
const tickerText = { fontSize: '0.75rem', fontWeight: 900, color: 'var(--accent-primary)', letterSpacing: '0.1em' };

const priceContainer = { display: 'flex', flexDirection: 'column', marginBottom: '1rem' };
const priceLabel = { fontSize: '0.5rem', color: 'var(--text-muted)', fontWeight: 800, letterSpacing: '0.2em' };
const priceText = { fontSize: '2rem', fontWeight: 900, color: 'var(--text-primary)', fontFamily: 'monospace' };

const changeRow = (up) => ({
    display: 'flex', alignItems: 'center', gap: '8px', padding: '8px 12px', borderRadius: '8px',
    background: up ? 'rgba(16,185,129,0.05)' : 'rgba(239,68,68,0.05)',
    color: up ? '#10b981' : '#ef4444', fontSize: '0.85rem'
});

const emptyState = { gridColumn: '1/-1', textAlign: 'center', padding: '6rem', color: 'var(--text-muted)', fontFamily: 'monospace', border: '1px dashed var(--surface-border)', borderRadius: '24px' };

export default LiveMarketPage;
